// Promise basics
function fetchUser(id) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (id > 0) {
        resolve({ id, name: `User ${id}`, email: `user${id}@ex.com` });
      } else {
        reject(new Error("Invalid user ID"));
      }
    }, 1000);
  });
}

// Promise chaining
fetchUser(1)
  .then(user => fetchUser(user.id + 1))
  .then(user => console.log(user.name))
  .catch(err => console.error(err.message));

// Async/await (preferred)
async function loadUsers() {
  try {
    const user1 = await fetchUser(1);
    const user2 = await fetchUser(2);
    return [user1, user2];
  } catch (err) {
    console.error("Failed:", err.message);
    return [];
  }
}

// Parallel execution
async function loadAll() {
  const [user1, user2, user3] = await Promise.all([
    fetchUser(1),
    fetchUser(2),
    fetchUser(3),
  ]);
  return [user1, user2, user3];
}

// Race â€” first to resolve wins
async function fetchWithTimeout(url, ms) {
  const fetchPromise = fetch(url);
  const timeout = new Promise((_, reject) =>
    setTimeout(() => reject(new Error("Timeout")), ms)
  );
  return Promise.race([fetchPromise, timeout]);
}

// Promise.allSettled â€” wait for all, don't short-circuit
const results = await Promise.allSettled([
  fetchUser(1),
  fetchUser(-1),  // will reject
  fetchUser(3),
]);
results.forEach(r => {
  if (r.status === "fulfilled") console.log("OK:", r.value);
  else console.log("FAIL:", r.reason.message);
});

// Event loop order
console.log("1: sync");
setTimeout(() => console.log("2: macrotask"), 0);
Promise.resolve().then(() => console.log("3: microtask"));
console.log("4: sync");
// Output: 1, 4, 3, 2
