// Private fields (#)
class BankAccount {
  #balance = 0;
  #log = [];

  constructor(owner) {
    this.owner = owner;
  }

  deposit(amount) {
    if (amount <= 0) throw new Error("Amount must be positive");
    this.#balance += amount;
    this.#log.push({ type: "deposit", amount, date: new Date() });
    return this;
  }

  get balance() { return this.#balance; }
  get history() { return [...this.#log]; }
}

const acct = new BankAccount("Alice");
acct.deposit(100).deposit(50);
console.log(acct.balance); // 150
// console.log(acct.#balance); // SyntaxError!

// Nullish coalescing (??) vs logical OR (||)
const config = { timeout: 0, retries: null, name: "" };
console.log(config.timeout ?? 3000);  // 0 (0 is not nullish)
console.log(config.timeout || 3000);  // 3000 (0 is falsy!)
console.log(config.retries ?? 3);     // 3 (null is nullish)
console.log(config.name ?? "default"); // "" ("" is not nullish)

// Optional chaining
