// Custom error classes
class AppError extends Error {
  constructor(message, code, details = {}) {
    super(message);
    this.name = "AppError";
    this.code = code;
    this.details = details;
  }
}

class ValidationError extends AppError {
  constructor(field, message) {
    super(message, "VALIDATION_ERROR", { field });
    this.name = "ValidationError";
    this.field = field;
  }
}

class NotFoundError extends AppError {
  constructor(resource, id) {
    super(`${resource} #${id} not found`, "NOT_FOUND");
    this.name = "NotFoundError";
  }
}

// Async error handling
async function safeApiCall(url) {
  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new AppError(`HTTP ${response.status}`, "HTTP_ERROR");
    }
    return await response.json();
  } catch (err) {
    if (err instanceof AppError) {
      console.error(`[${err.code}] ${err.message}`);
    } else if (err.name === "AbortError") {
      console.error("Request was cancelled");
    } else {
      console.error("Unexpected error:", err);
    }
    throw err; // re-throw for caller
  }
}

// Debugging tools
console.table([
  { name: "Alice", score: 95 },
  { name: "Bob", score: 87 },
]);

console.time("array-build");
const big = Array.from({ length: 1_000_000 }, (_, i) => i);
console.timeEnd("array-build"); // ~50ms

console.group("User Operations");
console.log("Fetching user...");
